프로젝트 구조를 충분히 파악했습니다. 기존 스키마/프로토 파일은 없는 초기 상태입니다. entity-skill에서 확인한 카탈로그 정보에 따르면 `profile`은 `maum` 카탈로그에 속합니다. 이제 프로필 수정 API를 설계하겠습니다.

---

# 프로필 수정 API 설계

## 1. 현재 프로젝트 구조 분석 결과

기존 `.graphqls` 파일과 `.proto` 파일이 없는 초기 상태입니다. 스킬 문서에서 확인한 컨벤션을 기준으로 설계합니다.

- GraphQL 스키마 위치: `graphql/src/main/resources/graphql/schema.graphqls` 또는 도메인별 `.graphqls`
- Proto 위치: `protobuf/src/main/proto/profile/profile.proto`
- DB 카탈로그: `maum` (profile 도메인)

---

## 2. GraphQL 뮤테이션 스키마 (클라이언트용)

파일 위치: `graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# ─────────────────────────────────────────────
# 타입 정의
# ─────────────────────────────────────────────

type Profile {
    userId: ID!
    nickname: String!
    birthYear: Int!
    gender: Gender!
    bio: String
    profileImages: [ProfileImage!]!
    height: Int
    job: String
    mbti: String
    interests: [String!]!
    updatedAt: String!
}

type ProfileImage {
    id: ID!
    url: String!
    order: Int!
    isMain: Boolean!
}

enum Gender {
    MALE
    FEMALE
}

# ─────────────────────────────────────────────
# Input 정의
# ─────────────────────────────────────────────

input UpdateProfileInput {
    nickname: String
    bio: String
    height: Int
    job: String
    mbti: Mbti
    interests: [String!]
    profileImages: [ProfileImageInput!]
}

input ProfileImageInput {
    id: ID
    url: String!
    order: Int!
    isMain: Boolean!
}

enum Mbti {
    INTJ
    INTP
    ENTJ
    ENTP
    INFJ
    INFP
    ENFJ
    ENFP
    ISTJ
    ISFJ
    ESTJ
    ESFJ
    ISTP
    ISFP
    ESTP
    ESFP
}

# ─────────────────────────────────────────────
# Query / Mutation 확장
# ─────────────────────────────────────────────

extend type Query {
    myProfile: Profile!
    profile(userId: ID!): Profile
}

extend type Mutation {
    updateProfile(input: UpdateProfileInput!): Profile!
}
```

### 필드별 유효성 검증 규칙 (GraphQL 레이어)

| 필드 | 타입 | Nullable | 규칙 |
|------|------|----------|------|
| `nickname` | String | O (부분 수정) | 2~20자, 공백 불가, 특수문자 제한 |
| `bio` | String | O | 최대 200자 |
| `height` | Int | O | 140 ~ 220 범위 |
| `job` | String | O | 최대 30자 |
| `mbti` | Mbti enum | O | 16개 유효 값으로 제한 |
| `interests` | [String!] | O | 최대 10개, 항목당 최대 15자 |
| `profileImages` | [ProfileImageInput!] | O | 최대 6장, isMain이 1개 이상 필수 |
| `profileImages[].url` | String | X | HTTPS URL 형식 |
| `profileImages[].order` | Int | X | 1~6 범위 |

---

## 3. gRPC Proto 정의 (서비스 간 통신용)

파일 위치: `protobuf/src/main/proto/profile/profile.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ─────────────────────────────────────────────
// Service 정의
// ─────────────────────────────────────────────

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}

// ─────────────────────────────────────────────
// Enum
// ─────────────────────────────────────────────

enum Gender {
  GENDER_UNSPECIFIED = 0;
  GENDER_MALE        = 1;
  GENDER_FEMALE      = 2;
}

// ─────────────────────────────────────────────
// 공통 메시지
// ─────────────────────────────────────────────

message ProfileMessage {
  string   user_id        = 1;
  string   nickname       = 2;
  int32    birth_year     = 3;
  Gender   gender         = 4;
  string   bio            = 5;
  repeated ProfileImageMessage profile_images = 6;
  optional int32  height  = 7;
  optional string job     = 8;
  optional string mbti    = 9;
  repeated string interests = 10;
  string   updated_at    = 11;
}

message ProfileImageMessage {
  string  id      = 1;
  string  url     = 2;
  int32   order   = 3;
  bool    is_main = 4;
}

// ─────────────────────────────────────────────
// GetProfile
// ─────────────────────────────────────────────

message GetProfileRequest {
  string user_id        = 1;
  string requester_id   = 2;  // 조회자 ID (차단 여부 등 확인용)
}

message GetProfileResponse {
  ProfileMessage profile = 1;
}

// ─────────────────────────────────────────────
// UpdateProfile
// ─────────────────────────────────────────────

message UpdateProfileRequest {
  string user_id = 1;

  optional string nickname = 2;
  optional string bio      = 3;
  optional int32  height   = 4;
  optional string job      = 5;
  optional string mbti     = 6;
  repeated string interests      = 7;
  repeated ProfileImageInput profile_images = 8;

  // 부분 수정 지원을 위한 update_mask
  // 예: ["nickname", "bio", "height"]
  repeated string update_mask = 9;
}

message ProfileImageInput {
  optional string id      = 1;  // 기존 이미지인 경우 ID 포함
  string          url     = 2;
  int32           order   = 3;
  bool            is_main = 4;
}

message UpdateProfileResponse {
  ProfileMessage profile = 1;
}
```

