## 4. GraphQL Controller / Service 계층 구조

### GraphQL Controller

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getProfile(userId, requesterId = userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun profile(
        @UserId userId: String,
        @Argument userId: String,           // 조회 대상
    ): ProfileResponse? {
        val response = profileService.getProfile(targetUserId = userId, requesterId = userId)
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): ProfileResponse {
        val response = profileService.updateProfile(userId, input)
        return response.profile.toResponse()
    }
}
```

### GraphQL Service (gRPC Client)

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getProfile(targetUserId: String, requesterId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setUserId(targetUserId)
            .setRequesterId(requesterId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.NOT_FOUND -> throw CustomGraphQLException("NOT_FOUND", e.status.description)
                else -> throw CustomGraphQLException(e.trailers!!, e.status.description)
            }
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        // update_mask 기반 부분 수정
        val mask = mutableListOf<String>()
        input.nickname?.let { builder.setNickname(it); mask.add("nickname") }
        input.bio?.let { builder.setBio(it); mask.add("bio") }
        input.height?.let { builder.setHeight(it); mask.add("height") }
        input.job?.let { builder.setJob(it); mask.add("job") }
        input.mbti?.let { builder.setMbti(it.name); mask.add("mbti") }
        input.interests?.let { builder.addAllInterests(it); mask.add("interests") }
        input.profileImages?.let {
            builder.addAllProfileImages(it.map { img -> img.toProto() })
            mask.add("profile_images")
        }

        builder.addAllUpdateMask(mask)

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.INVALID_ARGUMENT ->
                    throw CustomGraphQLException("BAD_REQUEST", e.status.description)
                Status.Code.NOT_FOUND ->
                    throw CustomGraphQLException("NOT_FOUND", e.status.description)
                else ->
                    throw CustomGraphQLException("INTERNAL", "프로필 서비스 오류")
            }
        }
    }
}
```

